#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long maxT, maxN, sumN;
        scanf("%lld %lld %lld", &maxT, &maxN, &sumN);
        long long k = sumN / maxN;
        if(k > maxT) k = maxT;
        long long ans = k * maxN * maxN;
        long long rem = sumN - k * maxN;
        if(k < maxT && rem > 0) ans += rem * rem;
        printf("%lld\n", ans);
    }
    return 0;
}

