import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            long maxT = Long.parseLong(st.nextToken());
            long maxN = Long.parseLong(st.nextToken());
            long sumN = Long.parseLong(st.nextToken());
            long k = sumN / maxN;
            if (k > maxT) k = maxT;
            long ans = k * maxN * maxN;
            long rem = sumN - k * maxN;
            if (k < maxT && rem > 0) ans += rem * rem;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

